import { html, customElement, property, css } from '@umbraco-cms/backoffice/external/lit';
import type { UmbPropertyEditorUiElement } from '@umbraco-cms/backoffice/property-editor';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import type { UUIInputEvent } from '@umbraco-ui/uui-input';

const elementName = "forms-standard-field-mapper-property-editor";

export type StandardFieldMapping = { field: string, include: boolean, keyName?: string }

@customElement(elementName)
export class FormsStandardFieldMapperPropertyUiElement extends UmbLitElement implements UmbPropertyEditorUiElement {

  #value: string = "";

  @property({ type: String })
  get value() { return this.#value; }
  set value(value: string) {
    const oldVal = this.#value;
    this.#value = value;
    this.requestUpdate('value', oldVal);

    this.#initializeMappings(value);
  }

  #mappings: Array<StandardFieldMapping> = [];

  #initializeMappings(value?: string) {
    if (value && value.length > 0) {
      this.#mappings = JSON.parse(value);
      this.#cleanMappings();
    }

    // Add standard mappings. We could add more to these after the initial release, so will make sure to
    // check each one to see if exists from the saved setting value.
    // Should include all defined in FormBuilderCore.Providers.Models.StandardFieldMapping.
    this.#ensureDefaultMapping("FormId");
    this.#ensureDefaultMapping("FormName");
    this.#ensureDefaultMapping("PageUrl");
    this.#ensureDefaultMapping("SubmissionDate");
  }

  #cleanMappings() {
    // Remove the tracking values added previously in angularjs.
    for (let index = 0; index < this.#mappings.length; index++) {
      const mapping = this.#mappings[index];
      delete mapping["$$hashKey"];
    }
  }

  #ensureDefaultMapping(fieldName) {
    if (!this.#hasMapping(fieldName)) {
      this.#mappings.push({
        field: fieldName,
        include: false
      });
    }
  }

  #hasMapping(fieldName) {
    return this.#mappings.find(m => m.field == fieldName) !== undefined
  }

  #getFriendlyName(field) {
    switch (field) {
      case "FormId":
        return "Form ID";
      case "FormName":
        return "Form name";
      case "PageUrl":
        return "Page URL";
      case "SubmissionDate":
        return "Submission date/time";
      default:
        return field;
    }
  }

  #onIncludeToggle(idx: number) {
    this.#mappings[idx].include = !this.#mappings[idx].include;
    this.#refreshValue();
  }

  #onKeyNameChange(e: UUIInputEvent, idx: number) {
    const value = e.target.value.toString();
    if (value.length > 0) {
      this.#mappings[idx].keyName = value;
    } else {
      this.#mappings[idx].keyName = undefined;
    }

    this.#refreshValue();
  }

  #refreshValue() {
    this.value = JSON.stringify(this.#mappings);
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  async connectedCallback() {
    super.connectedCallback();
  }

  render() {
    return html`<div class="umb-forms-mappings">

        <div class="umb-forms-mapping-header">
          <div class="umb-forms-mapping-field -no-margin-left">Field</div>
          <div class="umb-forms-mapping-field">Include?</div>
          <div class="umb-forms-mapping-field -no-margin-right">Key</div>
        </div>

        ${this.#mappings.map((mapping, idx) => html`
          <div class="umb-forms-mapping">
            <div class="umb-forms-mapping-field -no-margin-left">
              <span>${this.#getFriendlyName(mapping.field)}</span>
            </div>
            <div class="umb-forms-mapping-field" data-umb-standard-field-mapping-include="${mapping.field}">
              <uui-toggle
                ?checked=${mapping.include}
                @change=${() => this.#onIncludeToggle(idx)}
              ></uui-toggle>
            </div>
            <div class="umb-forms-mapping-field -no-margin-right" data-umb-standard-field-mapping-key-name="${mapping.field}">
              <uui-input
                type="text"
                label="Key"
                placeholder="Key name"
                .value=${mapping.keyName || ""}
                @change=${(e) => this.#onKeyNameChange(e, idx)}
              ></uui-input>
            </div>
          </div>`)}
      </div>`;
  }

  static styles = [
		css`
    .umb-forms-mappings {
      display: flex;
      flex-direction: column;
    }

    .umb-forms-mapping-header {
        display: flex;
        flex-direction: row;
        font-weight: bold;
    }

    .umb-forms-mapping {
        display: flex;
        flex-direction: row;
        margin-bottom: 5px;
        align-items: center;
    }

    .umb-forms-mapping-field {
        flex: 1 1 33%;
        margin: 5px;
    }

    .umb-forms-mapping-field input,
    .umb-forms-mapping-field select {
        margin-bottom: 0;
    }

    .umb-forms-mapping-field.-no-margin-left {
        margin-left: 0;
    }

    .umb-forms-mapping-remove {
        flex: 1 1 20px;
        margin: 5px;
    }


    .umb-forms-mapping-remove.-no-margin-right {
        margin-right: 0;
    }
		`,
  ];
}

export default FormsStandardFieldMapperPropertyUiElement;

declare global {
    interface HTMLElementTagNameMap {
        [elementName]: FormsStandardFieldMapperPropertyUiElement;
    }
}
